      // Cleanup on unmount
      onBeforeUnmount(() => {
        // Clear search timeout (memory leak fix)
        if (searchTimeout) {
          clearTimeout(searchTimeout);
          searchTimeout = null;
        }

        // Clean scroll listeners
        if (scrollCleanup) {
          scrollCleanup();
        }

        // Clear expansion state (memory leak fix)
        expandedTools.value = {};
        expandedContent.value = {};

        // Clear markdown cache (memory leak fix)
        markdownCache.clear();
      });
    });

    return {
      sessionId,
      metadata,
      exporting,
      sidebarCollapsed,
      expandedTools,
      expandedContent,
      expansionCount,
      currentFilter,
      searchText,
      currentTurnIndex,
      scrollerRef,
      visibleRange,
      loadedEvents,
      eventsLoading,
